import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { Trash2, Store, Plus, X, MapPin, Search } from 'lucide-react';

// --- CONFIGURACIÓN DE ICONOS ---
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';
let DefaultIcon = L.icon({
    iconUrl: markerIcon,
    shadowUrl: markerShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});
L.Marker.prototype.options.icon = DefaultIcon;

// Componente para mover la cámara del mapa cuando se encuentra una dirección
function ChangeView({ center }) {
  const map = useMap();
  map.setView(center, 16);
  return null;
}

const Dashboard = () => {
  const [locales, setLocales] = useState([
    { id: 1, nombre: "Mr. Drink", direccion: "Av. Manuel Belgrano 2800, Tucumán", coords: [-26.816, -65.230] }
  ]);
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [nuevoLocal, setNuevoLocal] = useState({ 
    nombre: '', 
    direccion: 'Laprida 934, Tafí Viejo, Tucumán', 
    coords: [-26.816, -65.216] 
  });

  // FUNCIÓN PARA BUSCAR COORDENADAS AUTOMÁTICAMENTE
  const buscarDireccion = async () => {
    if (!nuevoLocal.direccion) return;
    setLoading(true);
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(nuevoLocal.direccion)}`
      );
      const data = await response.json();
      if (data && data.length > 0) {
        const { lat, lon } = data[0];
        setNuevoLocal({ ...nuevoLocal, coords: [parseFloat(lat), parseFloat(lon)] });
      } else {
        alert("No se encontró la ubicación. Intenta ser más específico.");
      }
    } catch (error) {
      console.error("Error buscando dirección:", error);
    }
    setLoading(false);
  };

  const agregarLocal = (e) => {
    e.preventDefault();
    setLocales([...locales, { ...nuevoLocal, id: Date.now() }]);
    setShowModal(false);
  };

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 75px)', overflow: 'hidden', position: 'relative' }}>
      
      {/* SIDEBAR */}
      <div style={sidebarStyle}>
        <h2 style={{ fontSize: '1.5rem', marginBottom: '5px' }}>Mis Locales</h2>
        <div style={listaContenedor}>
          {locales.map(local => (
            <div key={local.id} style={cardLocal}>
              <div style={iconBox}><Store size={20} color="#e67e22" /></div>
              <div style={{ flex: 1 }}>
                <h4 style={{ margin: 0 }}>{local.nombre}</h4>
                <p style={{ margin: 0, fontSize: '0.8rem', color: '#64748b' }}>{local.direccion}</p>
              </div>
              <button onClick={() => setLocales(locales.filter(l => l.id !== local.id))} style={btnBorrar}><Trash2 size={18} /></button>
            </div>
          ))}
        </div>
        <button onClick={() => setShowModal(true)} style={btnNuevaSucursal}><Plus size={20} /> Nueva Sucursal</button>
      </div>

      {/* MAPA */}
      <div style={{ flex: 1 }}>
        <MapContainer center={nuevoLocal.coords} zoom={14} style={{ height: '100%', width: '100%' }}>
          <ChangeView center={nuevoLocal.coords} />
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {locales.map(local => (
            <Marker key={local.id} position={local.coords}>
              <Popup><strong>{local.nombre}</strong></Popup>
            </Marker>
          ))}
          {/* Marcador temporal de lo que se está buscando */}
          {showModal && <Marker position={nuevoLocal.coords} opacity={0.5} />}
        </MapContainer>
      </div>

      {/* MODAL */}
      {showModal && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <h3>Nueva Sucursal</h3>
              <X onClick={() => setShowModal(false)} style={{ cursor: 'pointer' }} />
            </div>
            <form onSubmit={agregarLocal}>
              <label style={labelStyle}>Nombre</label>
              <input style={inputStyle} required onChange={(e) => setNuevoLocal({...nuevoLocal, nombre: e.target.value})} />
              
              <label style={labelStyle}>Dirección (Calle Altura, Ciudad, Provincia)</label>
              <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
                <input 
                  style={{ ...inputStyle, marginBottom: 0 }} 
                  value={nuevoLocal.direccion}
                  onChange={(e) => setNuevoLocal({...nuevoLocal, direccion: e.target.value})}
                />
                <button type="button" onClick={buscarDireccion} style={btnCheck}>
                  <Search size={18} />
                </button>
              </div>

              <div style={coordsDisplay}>
                <MapPin size={16} color="#e67e22" />
                <span>Coordenadas: {nuevoLocal.coords[0].toFixed(4)}, {nuevoLocal.coords[1].toFixed(4)}</span>
              </div>

              <button type="submit" style={btnNuevaSucursal} disabled={loading}>
                {loading ? 'Buscando...' : 'Confirmar y Guardar'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

/* --- ESTILOS --- */
const sidebarStyle = { width: '400px', padding: '40px 25px', background: '#ffffff', display: 'flex', flexDirection: 'column', borderRight: '1px solid #e2e8f0' };
const listaContenedor = { flex: 1, overflowY: 'auto' };
const cardLocal = { display: 'flex', alignItems: 'center', padding: '20px', background: '#fff9f5', borderRadius: '16px', marginBottom: '15px', border: '1px solid #ffeada', gap: '15px' };
const iconBox = { background: '#ffffff', padding: '10px', borderRadius: '12px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' };
const btnBorrar = { background: 'transparent', border: 'none', color: '#f87171', cursor: 'pointer' };
const btnNuevaSucursal = { background: '#e67e22', color: 'white', padding: '15px', borderRadius: '12px', border: 'none', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', cursor: 'pointer', width: '100%' };
const btnCheck = { background: '#1e293b', color: 'white', border: 'none', padding: '10px', borderRadius: '10px', cursor: 'pointer' };
const modalOverlay = { position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.4)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 };
const modalContent = { background: 'white', padding: '30px', borderRadius: '20px', width: '400px' };
const modalHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const labelStyle = { display: 'block', marginBottom: '5px', fontSize: '0.85rem', fontWeight: '600' };
const inputStyle = { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #ddd', boxSizing: 'border-box' };
const coordsDisplay = { background: '#f1f5f9', padding: '10px', borderRadius: '10px', fontSize: '0.8rem', marginBottom: '20px', display: 'flex', gap: '10px', alignItems: 'center' };

export default Dashboard;
